INSERT INTO `dinky_task` VALUES (1,'DefaultCatalog',1,'FlinkSqlEnv',NULL,NULL,NULL,NULL,NULL,1,0,0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,'2025-06-20 13:14:00','2025-06-25 13:24:13',NULL,'create catalog my_catalog_dinky_mysql with(\n    \'type\' = \'dinky_mysql\',\n    \'username\' = \'dinky\',\n    \'password\' = \'dinky\',\n    \'url\' = \'jdbc:mysql://mysql:3306/dinky?useUnicode=true&characterEncoding=UTF-8&autoReconnect=true&useSSL=false&zeroDateTimeBehavior=convertToNull&serverTimezone=Asia/Shanghai&allowPublicKeyRetrieval=true\'\n);\nuse catalog my_catalog_dinky_mysql ;\n',1,1,1,1,NULL),(2,'mysql-jdbc-demo',1,'FlinkSql','yarn-session',NULL,0,NULL,1,0,1,0,1,NULL,NULL,-1,-1,NULL,NULL,1,1,1,'2025-06-20 13:26:34','2025-06-25 13:12:17',NULL,'CREATE TABLE mysql_jdbc_dinky_user (\n  id int,\n  username STRING,\n  user_type INT,\n  PRIMARY KEY (id) NOT ENFORCED\n) WITH (\n   \'connector\' = \'jdbc\',\n   \'url\' = \'jdbc:mysql://mysql:3306/dinky\',\n   \'table-name\' = \'dinky_user\',\n   \'username\' = \'root\',\n   \'password\' = \'root\'\n);\nselect * from mysql_jdbc_dinky_user;',1,1,1,1,NULL),(3,'mysql-cdc-demo',1,'FlinkSql','yarn-session',NULL,0,NULL,1,0,1,0,1,NULL,NULL,-1,-1,NULL,NULL,1,4,1,'2025-06-20 13:31:07','2025-06-20 13:31:55',NULL,'CREATE TABLE mysql_cdc_dinky_user(\n    id int,\n    username STRING,\n    user_type INT,\n    PRIMARY KEY (id) NOT ENFORCED\n) WITH (\n    \'connector\' = \'mysql-cdc\',\n    \'hostname\' = \'mysql\',\n    \'port\' = \'3306\',\n    \'username\' = \'root\',\n    \'password\' = \'root\',\n    \'database-name\' = \'dinky\',\n    \'scan.incremental.snapshot.enabled\' = \'true\',\n    \'debezium.snapshot.mode\'=\'INITIAL\',\n    \'table-name\' = \'dinky_user\'\n);\n\nselect * from mysql_cdc_dinky_user;',1,1,1,1,NULL),(4,'WordCountDemo',1,'FlinkJar','yarn-application',NULL,0,NULL,1,0,1,0,NULL,1,NULL,-1,-1,NULL,NULL,1,6,1,'2025-06-20 13:33:20','2025-06-20 13:41:42',NULL,'\nEXECUTE JAR WITH (\r\n\'uri\'=\'rs:///app/SocketWindowWordCount.jar\',\r\n\'main-class\'=\'org.apache.flink.streaming.examples.socket.SocketWindowWordCount\',\r\n\'args\'=\'base64@IC0taG9zdG5hbWUgZGlua3kgLS1wb3J0IDkwMDAg\',\r\n\'allowNonRestoredState\'=\'false\'\r\n);\r\n',1,1,1,1,NULL),(5,'realtime_mysq2doris',1,'FlinkSql','yarn-application',NULL,0,NULL,1,0,1,0,1,1,NULL,-1,-1,NULL,NULL,1,6,1,'2025-06-20 14:28:50','2025-06-20 17:40:59',NULL,'set execution.checkpointing.interval = 2s;\n\nCREATE TABLE `mysql_cdc_worker`(\n    `id` INT,\n    `name` STRING,\n    `salary` decimal(8,2),\n    `desc` STRING,\n    `ts` STRING,\n    PRIMARY KEY (id) NOT ENFORCED\n) WITH (\n    \'connector\' = \'mysql-cdc\',\n    \'hostname\' = \'mysql\',\n    \'port\' = \'3306\',\n    \'username\' = \'root\',\n    \'password\' = \'root\',\n    \'database-name\' = \'test\',\n    \'scan.incremental.snapshot.enabled\' = \'true\',\n    \'debezium.snapshot.mode\'=\'INITIAL\',\n    \'table-name\' = \'worker\'\n);\n\nCREATE TABLE `doris_worker` (\n  `id` INT,\n  `name` STRING,\n  `salary` decimal(8,2),\n  `desc` STRING,\n  `ts` STRING\n) WITH (\n      \'connector\' = \'doris\',\n      \'fenodes\' = \'doris:48030\',\n      \'table.identifier\' = \'test.worker\',\n      \'username\' = \'root\',\n      \'password\' = \'root\',\n      \'sink.label-prefix\' = \'doris_label\'\n);\n\nINSERT INTO `doris_worker`\nSELECT\n  `id`,\n  `name`,\n  `salary`,\n  `desc`,\n  `ts`\nfrom mysql_cdc_worker;',1,1,1,1,NULL),(6,'mysql2fluss-demo',1,'FlinkSql','yarn-per-job',NULL,0,NULL,1,0,1,0,1,1,NULL,-1,-1,NULL,NULL,1,3,1,'2025-06-23 17:32:04','2025-06-25 13:46:14',NULL,'set execution.checkpointing.interval=2s;\nSET execution.runtime-mode=streaming;\n\nCREATE TABLE if not exists `mysql_cdc_dinky_user`(\n    `id` int,\n    `username` STRING,\n    `user_type` INT,\n    PRIMARY KEY (`id`) NOT ENFORCED\n) WITH (\n    \'connector\' = \'mysql-cdc\',\n    \'hostname\' = \'mysql\',\n    \'port\' = \'3306\',\n    \'username\' = \'root\',\n    \'password\' = \'root\',\n    \'database-name\' = \'dinky\',\n    \'scan.incremental.snapshot.enabled\' = \'true\',\n    \'debezium.snapshot.mode\'=\'INITIAL\',\n    \'table-name\' = \'dinky_user\'\n);\n\nCREATE CATALOG fluss_catalog WITH (\n  \'type\' = \'fluss\',\n  \'bootstrap.servers\' = \'fluss:9123\'\n);\n\ncreate database if not exists `fluss_catalog`.`test`;\n\nCREATE TABLE if not exists `fluss_catalog`.`test`.`fluss_dinky_user`(\n    id int,\n    username STRING,\n    user_type INT,\n    PRIMARY KEY (id) NOT ENFORCED\n) WITH (\n     \'table.datalake.enabled\' = \'true\',\n     \'table.datalake.freshness\' = \'30s\'\n);\n\ninsert into `fluss_catalog`.`test`.`fluss_dinky_user`\nselect\n    `id`,\n    `username`,\n    `user_type`\nfrom  mysql_cdc_dinky_user;\n\n\n\n\n\n',1,1,1,1,NULL);
